#[allow(dead_code)]
impl<T> SharedPtr<T> {
    /// `true` if the owned pointer is non-null.
    pub fn exists(&self) -> bool {
        !self.px.is_null()
    }

    /// Borrow the pointee, or `None` if the pointer is null.
    ///
    /// # Safety
    /// `px` must point to a live `T` for the duration of the borrow.
    pub unsafe fn as_ref(&self) -> Option<&T> {
        if self.px.is_null() {
            None
        } else {
            unsafe { Some(&*self.px) }
        }
    }

    /// Mutably borrow the pointee, or `None` if the pointer is null.
    ///
    /// # Safety
    /// `px` must point to a live `T` with no other live borrows for the duration.
    pub unsafe fn as_mut(&mut self) -> Option<&mut T> {
        if self.px.is_null() {
            None
        } else {
            unsafe { Some(&mut *self.px) }
        }
    }
}

template <class T>
inline bool SharedPtr<T>::exists() const {
    return px != nullptr;
}

#[allow(dead_code)]
impl String {
    /// The string bytes, resolving the small-string optimization.
    ///
    /// # Safety
    /// The string must be live and unmodified for the borrow: in the heap case the returned
    /// slice aliases the allocation the first eight buffer bytes point to.
    pub unsafe fn as_bytes(&self) -> &[u8] {
        let data: *const u8 = if self.capacity < 16 {
            self.buffer.as_ptr()
        } else {
            unsafe { ::core::ptr::read_unaligned(self.buffer.as_ptr() as *const *const u8) }
        };
        unsafe { ::core::slice::from_raw_parts(data, self.size as usize) }
    }
}

#[allow(dead_code)]
impl<T> Vector<T> {
    /// Number of live elements.
    pub fn len(&self) -> usize {
        if self.begin.is_null() {
            0
        } else {
            (self.end as usize - self.begin as usize) / ::core::mem::size_of::<T>()
        }
    }

    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }

    /// The live elements as a slice.
    ///
    /// # Safety
    /// `begin..end` must point to `len()` live `T`s for the borrow.
    pub unsafe fn as_slice(&self) -> &[T] {
        if self.begin.is_null() {
            &[]
        } else {
            unsafe { ::core::slice::from_raw_parts(self.begin, self.len()) }
        }
    }

    /// The live elements as a mutable slice.
    ///
    /// # Safety
    /// `begin..end` must point to `len()` live `T`s for the borrow.
    pub unsafe fn as_slice_mut(&mut self) -> &mut [T] {
        if self.begin.is_null() {
            &mut []
        } else {
            unsafe { ::core::slice::from_raw_parts_mut(self.begin, self.len()) }
        }
    }
}

template <class T>
inline ::std::uint64_t Vector<T>::len() const {
    if (begin == nullptr) {
        return 0;
    }
    return static_cast<::std::uint64_t>(reinterpret_cast<const char*>(end) - reinterpret_cast<const char*>(begin)) / sizeof(T);
}

template <class T>
inline bool Vector<T>::is_empty() const {
    return len() == 0;
}

